import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { styles } from '../styles/styles';
import { API_URL } from '../constants';
import RatingModal from './RatingModal';
import { collaborativeFilterService } from '../services/collaborativeFilterService';
import { toast } from 'react-toastify';

function MovieCard({ movie }) {
  const navigate = useNavigate();
  const [showRatingModal, setShowRatingModal] = useState(false);

  // Construct full image URL if it's a relative path
  const getImageUrl = (imageUrl) => {
    if (!imageUrl) return null;
    if (imageUrl.startsWith('http')) {
      return imageUrl;
    }
    // For relative paths like /uploads/filename
    return `${API_URL.replace('/api', '')}${imageUrl}`;
  };

  const fullImageUrl = getImageUrl(movie.imageUrl);
  
  const userId = localStorage.getItem('userId') || '';
  
  const handleRateMovie = async (movieId, rating) => {
    try {
      await collaborativeFilterService.submitRating(userId, movieId, rating);
      toast.success(`Thank you for rating this movie ${rating}/10!`);
      // Optionally update the movie's rating in the UI
    } catch (error) {
      console.error('Error submitting rating:', error);
      toast.error('Failed to submit rating');
    }
  };

  return (
    <div
      style={styles.movieCard}
      onClick={() => navigate(`/movie/${movie._id}`)}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-10px)';
        e.currentTarget.style.boxShadow = '0 20px 40px rgba(233, 69, 96, 0.3)';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = 'none';
      }}
    >
      {fullImageUrl ? (
        <img src={fullImageUrl} alt={movie.title} style={styles.movieImage} />
      ) : (
        <div style={{ 
          ...styles.movieImage, 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'center', 
          fontSize: '48px' 
        }}>
          🎬
        </div>
      )}
      <div style={styles.movieInfo}>
        <h3 style={styles.movieTitle}>{movie.title}</h3>
        <div style={styles.movieMeta}>
          <span style={styles.genreBadge}>{movie.genre}</span>
          <span style={styles.rating}>⭐ {movie.rating.toFixed(1)}</span>
        </div>
        <p style={{ color: '#a0a0a0', fontSize: '14px' }}>
          {movie.releaseYear} • {movie.duration} min
        </p>
        
        <button
          onClick={(e) => {
            e.stopPropagation();
            setShowRatingModal(true);
          }}
          style={{
            marginTop: '10px',
            padding: '6px 12px',
            backgroundColor: '#e94560',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer',
            fontSize: '12px',
            fontWeight: '500'
          }}
        >
          Rate Movie
        </button>
      </div>
      
      <RatingModal
        isOpen={showRatingModal}
        onClose={() => setShowRatingModal(false)}
        onSubmit={handleRateMovie}
        movie={movie}
      />
    </div>
  );
}

export default MovieCard;
